import numpy as np
from collections import deque

def solve(grid):
    grid = np.array(grid)
    H, W = grid.shape
    output = np.full((H, W), 8)

    # Find shapes (connected components of 1s and 3s)
    shape_mask = (grid == 1) | (grid == 3)
    labels = np.zeros((H, W), dtype=int)
    shape_count = 0
    shapes = {}

    for r in range(H):
        for c in range(W):
            if shape_mask[r, c] and labels[r, c] == 0:
                shape_count += 1
                sid = shape_count
                queue = deque([(r, c)])
                labels[r, c] = sid
                cells = [(r, c)]
                while queue:
                    cr, cc = queue.popleft()
                    for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                        nr, nc = cr+dr, cc+dc
                        if 0 <= nr < H and 0 <= nc < W and labels[nr, nc] == 0 and shape_mask[nr, nc]:
                            labels[nr, nc] = sid
                            queue.append((nr, nc))
                            cells.append((nr, nc))
                shapes[sid] = cells

    # For each shape, compute green connector info
    shape_info = {}
    for sid, cells in shapes.items():
        green_cells = [(r, c) for r, c in cells if grid[r, c] == 3]
        blue_cells = [(r, c) for r, c in cells if grid[r, c] == 1]

        if not green_cells:
            continue

        blue_rs = [r for r, c in blue_cells]
        blue_cs = [c for r, c in blue_cells]
        green_rs = [r for r, c in green_cells]
        green_cs = [c for r, c in green_cells]

        bcr = sum(blue_rs) / len(blue_rs)
        bcc = sum(blue_cs) / len(blue_cs)
        gcr = sum(green_rs) / len(green_rs)
        gcc = sum(green_cs) / len(green_cs)

        dr = gcr - bcr
        dc = gcc - bcc

        if abs(dr) > abs(dc):
            direction = 'down' if dr > 0 else 'up'
        else:
            direction = 'right' if dc > 0 else 'left'

        if direction in ('up', 'down'):
            perp = sorted(set(green_cs))
        else:
            perp = sorted(set(green_rs))

        all_rs = [r for r, c in cells]
        all_cs = [c for r, c in cells]

        shape_info[sid] = {
            'cells': set(cells),
            'direction': direction,
            'perp': perp,
            'min_r': min(all_rs),
            'max_r': max(all_rs),
            'min_c': min(all_cs),
            'max_c': max(all_cs),
        }

    # Find arrow
    arrow_r, arrow_c = None, None
    for r in range(H):
        for c in range(W):
            if grid[r, c] == 4:
                arrow_r, arrow_c = r, c

    # Mark arrow and original red cells
    output[arrow_r, arrow_c] = 2
    for r in range(arrow_r + 1, H):
        if grid[r, arrow_c] == 2:
            output[r, arrow_c] = 2
        else:
            break

